import{_ as e,o as a,c as t,j as p,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"童话-梦魇","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/3.心智类/童话-梦魇.md","filePath":"4.资源分区/1.血统与训练/3.心智类/童话-梦魇.md"}'),b={name:"4.资源分区/1.血统与训练/3.心智类/童话-梦魇.md"};function d(o,r,l,_,i,c){return a(),t("div",null,[...r[0]||(r[0]=[p("h1",{id:"童话-梦魇",tabindex:"-1"},[n("童话-梦魇 "),p("a",{class:"header-anchor",href:"#童话-梦魇","aria-label":'Permalink to "童话-梦魇"'},"​")],-1),p("table",{class:"bannerparthead"},[p("tbody",null,[p("tr",{id:"hdr"},[p("td",{class:"runninghead",nowrap:""},"TMD：绯红庆典040")])])],-1),s('<h1 id="童话-梦魇-1" tabindex="-1">童话-梦魇 <a class="header-anchor" href="#童话-梦魇-1" aria-label="Permalink to &quot;童话-梦魇&quot;">​</a></h1><p>童话/梦魇</p><p>童话/梦魇（Fable/Nightmare）是对某些奇特种族的统称，没人知道她们是怎么诞生的，但是有些人推测她们来自那些人类曾经的童话故事。</p><p>无论这个童话/梦魇存在了多久，她们在撕破伪装前看上去都像是普通的人类孩子的模样，隐藏在人群中，并以人类的负面情感为食，诸如恐惧、绝望、嫉妒、悲伤等。</p><p>并非每个童话/梦魇都会袭击人类以获取食物，但是所有的童话/梦魇都不喜欢自己的身份被发现。</p><p>D级：故事残篇<br> D+600</p><p>「她们在墙缝、课桌、梦的皱褶中低语；那声音像童年的摇篮曲，却在回响里夹着冷意。」</p><p>每个童话/梦魇都拥有自己的故事原型，或许籍籍无名，也可能广为传唱，但对于现在的你来说，力量略有些薄弱。</p><p>你需要选定或自行创作/改编一篇童话故事作为原型，并在此基础上提炼一个问句作为核心。如“这场永不停歇的舞会何时才会停止？” “谁是猎物，谁是猎人？” “何时从长梦中醒来？”等。这将成为你追寻答案的目标。如果你觉得合适，那么在每场影片结束后，你可以更换自己的问题，但它需要与你的故事有所关联。</p><p>你获得噩梦能量池，属性为感知+操控。</p><p>噩梦无法通过正常方式进行回复，而转化为：</p><p>在战斗外，你可以花费15分钟，停留在某一处或进行不剧烈的走动。在此过程中，你的敏感范围内如果具有至少1个保持消极情感的生物，那么都会使此能量池恢复1d6点。在此基础上，人数达到10人/100人/1000人/以此类推，都会额外为你提供一枚1d6的恢复。不具有灵魂的生物（如死灵）以及机器人无法满足需求。</p><p>如果你在一天内至少满足过一次上述恢复条件，无论你是否恢复了能量，在进行长休时都可以回满噩梦能量池。否则你只能恢复一半的能量，并视为此日没有进行长休，受到缺乏长休的惩罚，无论你是否拥有无需休息特性。</p><p>每日最多只能恢复此能量池大小3倍的能量。</p><p>噩梦的基础用法：<br> - 当你进行一项感知属性相关检定时，花费1点噩梦，获得1点士气加值。</p><p>在没有变身时，你看起来就像人类儿童或少年少女，年龄只会停留在8~16岁之间，完美无瑕，但仍会受伤，与正常人无异。这是你的本体，也是你最好的伪装。如果你的体积高于4，则会变为4点，此形态下的体积无法通过购买任何资源改变。</p><p>同时在此形态下，你获得D级心灵来源的读心效果。以一个花招动作使用感知-洞察-读心专业对抗对方的意志豁免出目，成功则获悉对方心里最恐惧的事物。</p><p>通常来说你并不情愿这样做，你可以花费2点噩梦和一个移动动作保持不动以变身为梦魇形态。梦魇形态下，你展现出人类潜意识里最黑暗、最令人恐惧的自我。你的身体结构看起来就像来自最深的噩梦中般扭曲，同时展露出你的童话原型中的部分特征。</p><p>梦魇形态持续一场景，在你陷入昏迷时解除，或在战斗外主动解除。在此期间你获得以下效果：<br> - 你获得1点快速医疗（医疗点12）。<br> - 获得一种新的施法方式【梦魇】，使用【感知+洞察+洞察：读心+表达：精神污染】，攻击距离15m，造成精神伤害。具有3点基础法术强度，此种施法方式附带1点心灵影响来源的恐惧点数，标准豁免。</p><p>C级：梦之始<br> C+1200</p><p>「梦在她们指尖被编织成线，悲伤被染成银色，恐惧被打成结。」</p><p>童话/梦魇不会遗忘自己的问题。就像故事一样，这个问句也是你们本质的一部分，你总会找到它的答案的，或许就是明天。在一场影片结束后，你可以选择给你的问题写下一个答案。你可以在此时更换你的问题，也可以不更换。当你第一次写下答案时，你的外貌提升5点。</p><p>你学会了如何隐藏自己，在人群中，在心灵中。这是每个童话/梦魇想要在思想上更进一步所必须的。当你不处于梦魇形态时，你获得D级特异本质的反侦测，就像是你主动降低了自己在人群中的存在感、能够与人聊天却不被在意到是和谁在说话等。同时，你为自己的故事选定了本质，从以下效果中选一个获得，之后不可更改：</p><p>下列能力来源等级等同于资源等级</p><p>沉默的心灵<br> - 你想要逃避那些痛苦，带来着安宁与庇护。你想要吞噬那些意志，让它们永不苏醒。<br> - 当你变身为梦魇形态时，你的施法攻击带有C级心灵来源的沉默效果，意志豁免。</p><p>浪漫的心灵<br> - 你期望人与人间的爱与连接，带来温柔与欢喜。你扭曲那些情感与愿望，让它们走上错误的路。<br> - 当你变身为梦魇形态时，你的施法攻击命中后可以将伤害转化成等量的心灵来源的魅惑点数，意志豁免。</p><p>暴戾的心灵<br> - 你渴望打破枷锁，带来拯救与掌控。你燃烧情感与怒火，直至灰烬。<br> - 当你变身为梦魇形态时，你的施法攻击会附带等量的心灵来源的亢奋点数，意志豁免，你具有【激昂】。</p><p>渴求的心灵<br> - 你好奇一切，探索一切，带来永恒与创造。你占有万物，把它们变成自己的碎片。<br> - 当你变身为梦魇形态时，你具有基于士气防御的【劣化1】。</p><p>虚荣的心灵<br> - 你希望被注视，被认可，带来光明与美感。你拒绝现实的情感，主掌幻境中的王国。<br> - 当你变身为梦魇形态时，每轮一次，你可以重投【梦魇】检定的结果，但必须接受重投后的结果。</p><p>纠缠的心灵<br> - 你渴望理解它人之心，带来共情与慰藉。你妒忌那些情感和特质，就像不曾拥有过自己的。<br> - 当你变身为梦魇形态时，你的施法攻击带有C级心灵来源的混乱效果，意志豁免。</p><p>空洞的心灵<br> - 你想与世界融为一体，带来虚无与存续。你用那些情感和意识填补空虚，你从未满足。<br> - 当你变身为梦魇形态时，你的施法攻击带有【吸血1】，并在造成伤害时施加1点精神伤害易伤，持续到你的下回合结束。</p><p>B级：故事之孽<br> B+2400</p><p>「她们的名字曾在古老的纸页上被涂抹，却在被遗忘的角落再度书写。」</p><p>现在，你见识过了无数强烈的情感，你的本质趋近于完整，你会明确自己的道路，没人再能说服你改变自己，除非如你所愿。你免疫B级心灵来源效果。同时，你不处于梦魇形态时，你具有的反侦测升级到C。</p><p>有些童话/梦魇喜欢以温和的方式讲述童话，还有一些则更偏好一些充满刺激的手段。无论以什么方式，仅一次，当你在一场影片中传播过自己的故事后，你再提升5点外貌，并获得1点机运骰加值。</p><p>在梦魇形态中，你的规则开始显现。你需要花费10点噩梦和一个移动动作变身为梦魇形态。你的向周围展开自己的内心，就像梦境撕开了现实的面纱。周围的空间会受到你故事的污染，出现多余的物品，并尝试排斥那些不属于故事中的人。</p><p>梦魇形态持续一场景，在你陷入昏迷时解除，或在战斗外主动解除。于梦魇形态时，在本血统D级提供的效果基础上额外获得以下效果：</p><p>你的施法攻击额外具有【破魔5】。</p><p>你的【梦魇】攻击可以同时攻击射程范围内的所有单位。</p><p>这是你的梦，你想象中的一切展现于其中。在进入此梦境时，你会于现实中消失，而其他人则看上去就像是陷入了睡眠。</p><p>变身梦魇时后，你可以标准动作对所有处于你【梦魇】射程范围内的单位进行一次【梦魇】检定，但不视为攻击检定，对抗对方的意志豁免出目，成功则对方被拉入你的梦魇叙述域，其范围为你的敏感范围，这是一个B级心灵来源的异空间效果。</p><p>你可以主动退出异空间，但若如此做，则这片空间会消散，其他单位会返回原本所处的世界。</p><p>进入该异空间的目标会在战斗结束后回归原本的世界。</p><p>所有处于梦魇叙事域的单位将被梦境侵蚀，受到B级心灵来源的潮湿效果。</p><p>A级： 梦主<br> A+4800</p><p>「她们张开手指，世界化为书页；风、血、时间与命运，都在她们的叙事中翻动。」</p><p>你不再需要回答你的问题，因为有时问题本身便是答案。在万千世界中，你代表了你的故事本身，你或许不是它的起始，但你就是它的终章。你是角色，也是作者，你的言语和情感化作利刃，刺入人们的心灵。</p><p>当你未变身为梦魇形态时，你可以在战斗外跟一个与你交谈1分钟的单位使用感知-洞察-读心专业对抗对方的意志豁免出目，失败的话则会受到你的指使，进行符合你的故事中逻辑的行为，但无法因此伤害自己。这是一个B级精神控制效果。同时，你不处于梦魇形态时，你具有的反侦测升级到A。</p><p>众所周知，故事不灭。当你死亡时，你可以在一周后复活。在此期间你会变成灵体形式，且具有等同于你意志值的结构值，看上去就像是某种抽象的，不断交替并融合的符号，或是某种气味，如果结构值归零，则复活失败，这是一个心灵来源的A级复活效果。</p><p>当你变身为梦魇形态时：</p><p>- 你的【梦魇】攻击射程范围提升至敏感范围。</p><p>- 展开梦魇叙事域具有的异空间效果提升为A级。</p><p>-【梦魇】攻击具有【接触攻击】特性。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',55)])])}const m=e(b,[["render",d]]);export{f as __pageData,m as default};
